15	//! ⚠️ WARNING ⚠️
16	//!
17	//! This crate should be considered unstable, as in we might change the APIs anytime.
18	//!
19	//! This crate provides the traits to be implemented by a zenoh backend library:
20	//!  - [`Volume`]
21	//!  - [`Storage`]
22	//!
23	//! Such library must also declare a `create_volume()` operation
24	//! with the `#[no_mangle]` attribute as an entrypoint to be called for the Backend creation.
25	//!
26	//! # Example
27	//! ```
28	//! use std::sync::Arc;
29	//! use async_trait::async_trait;
30	//! use zenoh::{key_expr::OwnedKeyExpr, time::Timestamp, bytes::{ZBytes, Encoding}};
31	//! use zenoh_backend_traits::*;
32	//! use zenoh_backend_traits::config::*;
33	//! use zenoh_plugin_trait::{plugin_long_version, plugin_version, Plugin};
34	//! use zenoh_result::ZResult;
35	//! use zenoh_util::ffi::JsonValue;
36	//!
37	//!
38	//! // Your Backend volume implementation
39	//! struct MyVolumeType {
40	//!     config: VolumeConfig,
41	//! }
42	//!
43	//! // Create the entry point for your backend
44	//! zenoh_plugin_trait::declare_plugin!(MyVolumeType);
45	//!
46	//! impl Plugin for MyVolumeType {
47	//!     type StartArgs = VolumeConfig;
48	//!     type Instance = VolumeInstance;
49	//!     fn start(_name: &str, _args: &Self::StartArgs) -> ZResult<Self::Instance> {
50	//!         let volume = MyVolumeType {config: _args.clone()};
51	//!         Ok(Box::new(volume))
52	//!     }
53	//!
54	//!     const DEFAULT_NAME: &'static str = "my_backend";
55	//!     const PLUGIN_VERSION: &'static str = plugin_version!();
56	//!     const PLUGIN_LONG_VERSION: &'static str = plugin_long_version!();
57	//! }
58	//!
59	//!
60	//!
61	//! #[async_trait]
62	//! impl Volume for MyVolumeType {
63	//!     fn get_admin_status(&self) -> JsonValue {
64	//!         // This operation is called on GET operation on the admin space for the Volume
65	//!         // Here we reply with a static status (containing the configuration properties).
66	//!         // But we could add dynamic properties for Volume monitoring.
67	//!         self.config.to_json_value().into()
68	//!     }
69	//!
70	//!     fn get_capability(&self) -> Capability {
71	//!         // This operation is used to confirm if the volume indeed supports
72	//!         // the capabilities requested by the configuration
73	//!         Capability{
74	//!             persistence: Persistence::Volatile,
75	//!             history: History::Latest,
76	//!         }
77	//!     }
78	//!
79	//!     async fn create_storage(&self, properties: StorageConfig) -> zenoh::Result<Box<dyn Storage>> {
80	//!         // The properties are the ones passed via a PUT in the admin space for Storage creation.
81	//!         Ok(Box::new(MyStorage::new(properties).await?))
82	//!     }
83	//! }
84	//!
85	//! // Your Storage implementation
86	//! struct MyStorage {
87	//!     config: StorageConfig,
88	//! }
89	//!
90	//! impl MyStorage {
91	//!     async fn new(config: StorageConfig) -> zenoh::Result<MyStorage> {
92	//!         Ok(MyStorage { config })
93	//!     }
94	//! }
95	//!
96	//! #[async_trait]
97	//! impl Storage for MyStorage {
98	//!     fn get_admin_status(&self) -> JsonValue {
99	//!         // This operation is called on GET operation on the admin space for the Storage
100	//!         // Here we reply with a static status (containing the configuration properties).
101	//!         // But we could add dynamic properties for Storage monitoring.
102	//!         self.config.to_json_value().into()
103	//!     }
104	//!
105	//!     async fn put(&mut self, key: Option<OwnedKeyExpr>, payload: ZBytes, encoding: Encoding, timestamp: Timestamp) -> zenoh::Result<StorageInsertionResult> {
106	//!         // the key will be None if it exactly matched with the strip_prefix
107	//!         // create a storage specific special structure to store it
108	//!         // Store the data with timestamp
109	//!         // @TODO:
110	//!         // store (key, value, timestamp)
111	//!         return Ok(StorageInsertionResult::Inserted);
112	//!         //  - if any issue: drop
113	//!         // return Ok(StorageInsertionResult::Outdated);
114	//!     }
115	//!
116	//!     async fn delete(&mut self, key: Option<OwnedKeyExpr>, timestamp: Timestamp) -> zenoh::Result<StorageInsertionResult> {
117	//!         // @TODO:
118	//!         // delete the actual entry from storage
119	//!         return Ok(StorageInsertionResult::Deleted);
120	//!     }
121	//!
122	//!     // When receiving a GET operation
123	//!     async fn get(&mut self, key_expr: Option<OwnedKeyExpr>, parameters: &str) -> zenoh::Result<Vec<StoredData>> {
124	//!         // @TODO:
125	//!         // get the data associated with key_expr and return it
126	//!         // NOTE: in case parameters is not empty something smarter should be done with returned data...
127	//!         Ok(Vec::new())
128	//!     }
129	//!
130	//!     // To get all entries in the datastore
131	//!     async fn get_all_entries(&self) -> zenoh::Result<Vec<(Option<OwnedKeyExpr>, Timestamp)>> {
132	//!         // @TODO: get the list of (key, timestamp) in the datastore
133	//!         Ok(Vec::new())
134	//!     }
135	//! }
136	//! ```
137	
138	use async_trait::async_trait;
139	use zenoh::{
140	    bytes::{Encoding, ZBytes},
141	    key_expr::{keyexpr, OwnedKeyExpr},
142	    time::Timestamp,
143	    Result as ZResult,
144	};
145	use zenoh_plugin_trait::{PluginControl, PluginInstance, PluginStatusRec};
146	use zenoh_util::{concat_enabled_features, ffi::JsonValue};
147	
148	pub mod config;
149	use config::StorageConfig;
150	
151	// No features are actually used in this crate, but this dummy list allows to demonstrate how to combine feature lists
152	// from multiple crates. See impl `PluginStructVersion` for `VolumeConfig` below.
153	const FEATURES: &str =
154	    concat_enabled_features!(prefix = "zenoh-backend-traits", features = ["default"]);
155	
156	/// Capability of a storage indicates the guarantees of the storage
157	/// It is used by the storage manager to take decisions on the trade-offs to ensure correct performance
158	#[derive(Debug, Clone, PartialEq, Eq)]
159	pub struct Capability {
160	    pub persistence: Persistence,
161	    pub history: History,
162	}
163	
164	/// Persistence is the guarantee expected from a storage in case of failures
165	/// If a storage is marked Persistent::Durable, if it restarts after a crash, it will still have all the values that were saved.
166	/// This will include also persisting the metadata that Zenoh stores for the updates.
167	/// If a storage is marked Persistent::Volatile, the storage will not have any guarantees on its content after a crash.
168	/// This option should be used only if the storage is considered to function as a cache.
169	#[derive(Debug, Clone, PartialEq, Eq)]
170	pub enum Persistence {
171	    Volatile, //default
172	    Durable,
173	}
174	
175	/// History is the number of values that the backend is expected to save per key
176	/// History::Latest saves only the latest value per key
177	/// History::All saves all the values including historical values
178	#[derive(Debug, Clone, PartialEq, Eq)]
179	pub enum History {
180	    Latest, //default
181	    All,
182	}
183	
184	#[derive(Debug)]
185	pub enum StorageInsertionResult {
186	    Outdated,
187	    Inserted,
188	    Replaced,
189	    Deleted,
190	}
191	
192	#[derive(Debug, Clone)]
193	pub struct StoredData {
194	    pub payload: ZBytes,
195	    pub encoding: Encoding,
196	    pub timestamp: Timestamp,
197	}
198	
199	/// Trait to be implemented by a Backend.
200	#[async_trait]
201	pub trait Volume: Send + Sync {
202	    /// Returns the status in the json format that will be sent as a reply to a query
203	    /// on the administration space for this backend.
204	    fn get_admin_status(&self) -> JsonValue;
205	
206	    /// Returns the capability of this backend
207	    fn get_capability(&self) -> Capability;
208	
209	    /// Creates a storage configured with some properties.
210	    async fn create_storage(&self, props: StorageConfig) -> ZResult<Box<dyn Storage>>;
211	}
212	
213	pub type VolumeInstance = Box<dyn Volume + 'static>;
214	
215	impl PluginControl for VolumeInstance {
216	    fn plugins_status(&self, _names: &keyexpr) -> Vec<PluginStatusRec<'_>> {
217	        Vec::new()
218	    }
219	}
220	
221	impl PluginInstance for VolumeInstance {}
222	
223	/// Trait to be implemented by a Storage.
224	#[async_trait]
225	pub trait Storage: Send + Sync {
226	    /// Returns the status that will be sent as a reply to a query
227	    /// on the administration space for this storage.
228	    fn get_admin_status(&self) -> JsonValue;
229	
230	    /// Function called for each incoming data ([`Sample`](zenoh::sample::Sample)) to be stored in this storage.
231	    /// A key can be `None` if it matches the `strip_prefix` exactly.
232	    /// In order to avoid data loss, the storage must store the `value` and `timestamp` associated with the `None` key
233	    /// in a manner suitable for the given backend technology
234	    async fn put(
235	        &mut self,
236	        key: Option<OwnedKeyExpr>,
237	        payload: ZBytes,
238	        encoding: Encoding,
239	        timestamp: Timestamp,
240	    ) -> ZResult<StorageInsertionResult>;
241	
242	    /// Function called for each incoming delete request to this storage.
243	    /// A key can be `None` if it matches the `strip_prefix` exactly.
244	    /// In order to avoid data loss, the storage must delete the entry corresponding to the `None` key
245	    /// in a manner suitable for the given backend technology
246	    async fn delete(
247	        &mut self,
248	        key: Option<OwnedKeyExpr>,
249	        timestamp: Timestamp,
250	    ) -> ZResult<StorageInsertionResult>;
251	
252	    /// Function to retrieve the sample associated with a single key.
253	    /// A key can be `None` if it matches the `strip_prefix` exactly.
254	    /// In order to avoid data loss, the storage must retrieve the `value` and `timestamp` associated with the `None` key
255	    /// in a manner suitable for the given backend technology
256	    async fn get(
257	        &mut self,
258	        key: Option<OwnedKeyExpr>,
259	        parameters: &str,
260	    ) -> ZResult<Vec<StoredData>>;
261	
262	    /// Function called to get the list of all storage content (key, timestamp)
263	    /// The latest Timestamp corresponding to each key is either the timestamp of the delete or put whichever is the latest.
264	    /// Remember to fetch the entry corresponding to the `None` key
265	    async fn get_all_entries(&self) -> ZResult<Vec<(Option<OwnedKeyExpr>, Timestamp)>>;
266	}
