14	use std::{convert::TryFrom, time::Duration};
15	
16	use const_format::concatcp;
17	use derive_more::{AsMut, AsRef};
18	use either::Either;
19	use schemars::JsonSchema;
20	use serde_json::{Map, Value};
21	use zenoh::{
22	    key_expr::{keyexpr, OwnedKeyExpr},
23	    Result as ZResult,
24	};
25	use zenoh_plugin_trait::{PluginStartArgs, StructVersion};
26	use zenoh_result::{bail, zerror, Error};
27	use zenoh_util::{
28	    ffi::{JsonKeyValueMap, JsonValue},
29	    LibSearchDirs,
30	};
31	
32	#[derive(JsonSchema, Debug, Clone, AsMut, AsRef)]
33	pub struct PluginConfig {
34	    #[schemars(skip)]
35	    pub name: String,
36	    #[schemars(with = "Option<bool>")]
37	    pub required: bool,
38	    // REVIEW: This is inconsistent with `plugins_loading/search_dirs`
39	    #[schemars(with = "Option<Either<String, Vec<Either<Map<String, Value>, String>>>>")]
40	    pub backend_search_dirs: LibSearchDirs,
41	    #[schemars(with = "Map<String, Value>")]
42	    pub volumes: Vec<VolumeConfig>,
43	    #[schemars(with = "Map<String, Value>")]
44	    pub storages: Vec<StorageConfig>,
45	    #[as_ref]
46	    #[as_mut]
47	    #[schemars(skip)]
48	    pub rest: Map<String, Value>,
49	}
50	#[derive(JsonSchema, Debug, Clone, AsMut, AsRef)]
51	pub struct VolumeConfig {
52	    #[schemars(skip)]
53	    pub name: String,
54	    pub backend: Option<String>,
55	    pub paths: Option<Vec<String>>,
56	    pub required: bool,
57	    #[as_ref]
58	    #[as_mut]
59	    #[schemars(skip)]
60	    pub rest: JsonKeyValueMap,
61	}
62	#[derive(JsonSchema, Debug, Clone, PartialEq, Eq)]
63	pub struct StorageConfig {
64	    pub name: String,
65	    pub key_expr: OwnedKeyExpr,
66	    pub complete: bool,
67	    pub strip_prefix: Option<OwnedKeyExpr>,
68	    pub volume_id: String,
69	    pub volume_cfg: JsonValue,
70	    pub garbage_collection_config: GarbageCollectionConfig,
71	    // Note: ReplicaConfig is optional. Alignment will be performed only if it is a replica
72	    pub replication: Option<ReplicaConfig>,
73	}
74	// Note: All parameters should be same for replicas, else will result on huge overhead
75	#[derive(JsonSchema, Debug, Clone, PartialEq, Eq)]
76	pub struct ReplicaConfig {
77	    pub interval: Duration,
78	    pub sub_intervals: usize,
79	    pub hot: u64,
80	    pub warm: u64,
81	    pub propagation_delay: Duration,
82	}
83	
84	impl StructVersion for VolumeConfig {
85	    fn struct_version() -> &'static str {
86	        zenoh::GIT_VERSION
87	    }
88	    fn struct_features() -> &'static str {
89	        concatcp!(zenoh::FEATURES, crate::FEATURES)
90	    }
91	}
92	
93	impl PluginStartArgs for VolumeConfig {}
94	
95	impl Default for ReplicaConfig {
96	    fn default() -> Self {
97	        Self {
98	            // This variable, expressed in SECONDS (f64), controls the frequency at which the
99	            // Digests are computed and published.
100	            //
101	            // This also determines the time up to which replicas might diverge.
102	            //
103	            // Its default value is 10.0 seconds.
104	            //
105	            // ⚠️ THIS VALUE SHOULD BE THE SAME FOR ALL REPLICAS.
106	            interval: Duration::from_secs_f64(10.0),
107	            // This variable dictates the number of sub-intervals, of equal duration, within an
108	            // interval.
109	            //
110	            // This is used to separate the publications in smaller batches when computing their
111	            // fingerprints. A value of `1` will effectively disable the sub-intervals.
112	            // Higher values will slightly increase the size of the `Digest` sent on the
113	            // network but will reduce the amount of information sent when aligning.
114	            //
115	            // Hence, the trade-off is the following: with higher values more information are sent
116	            // at every interval, with lower values more information are sent when
117	            // aligning.
118	            //
119	            // Its default value is 5.
120	            //
121	            // ⚠️ THIS VALUE SHOULD BE THE SAME FOR ALL REPLICAS.
122	            sub_intervals: 5,
123	            // The number of intervals that compose the "hot" era.
124	            //
125	            // Its default value is 6 which, with the default `interval` value, corresponds to the
126	            // last minute.
127	            //
128	            // ⚠️ THIS VALUE SHOULD BE THE SAME FOR ALL REPLICAS.
129	            hot: 6,
130	            // The number of intervals that compose the "warm" era.
131	            //
132	            // Its default value is 30 which, with the default `interval` value, corresponds to 5
133	            // minutes.
134	            //
135	            // ⚠️ THIS VALUE SHOULD BE THE SAME FOR ALL REPLICAS.
136	            warm: 30,
137	            // The average time, expressed in MILLISECONDS, it takes for a publication to reach a
138	            // storage.
139	            //
140	            // This value controls when the replication Digest is generated and, hence, published.
141	            // Assuming that the `interval` is set to 10.0 seconds, with a
142	            // `propagation_delay` of 250 milliseconds, the replication Digest
143	            // will be computed at ( n × 10.0 ) + 0.25 seconds.
144	            //
145	            // ⚠️ For the reason above, this value cannot be greater or equal than half of the
146	            //    duration of an `interval`.
147	            //
148	            // Its default value is 250 milliseconds.
149	            //
150	            // ⚠️ THIS VALUE SHOULD BE THE SAME FOR ALL REPLICAS.
151	            propagation_delay: Duration::from_millis(250),
152	        }
153	    }
154	}
