156	// The configuration for periodic garbage collection of metadata in storage manager
157	#[derive(JsonSchema, Debug, Clone, PartialEq, Eq)]
158	pub struct GarbageCollectionConfig {
159	    // The duration between two garbage collection events
160	    // The garbage collection will be scheduled as a periodic event with this period
161	    pub period: Duration,
162	    // The metadata older than this parameter will be garbage collected
163	    pub lifespan: Duration,
164	}
