176	pub enum ConfigDiff {
177	    DeleteVolume(VolumeConfig),
178	    AddVolume(VolumeConfig),
179	    DeleteStorage(StorageConfig),
180	    AddStorage(StorageConfig),
181	}
182	pub trait AsObject {
183	    fn as_object(&self) -> Option<&serde_json::Map<String, serde_json::Value>>;
184	}
185	impl AsObject for serde_json::Value {
186	    fn as_object(&self) -> Option<&serde_json::Map<String, serde_json::Value>> {
187	        self.as_object()
188	    }
189	}
190	impl AsObject for serde_json::Map<String, serde_json::Value> {
191	    fn as_object(&self) -> Option<&serde_json::Map<String, serde_json::Value>> {
192	        Some(self)
193	    }
