195	impl<S: Into<String> + AsRef<str>, V: AsObject> TryFrom<(S, &V)> for PluginConfig {
196	    type Error = Error;
197	    fn try_from((name, value): (S, &V)) -> Result<Self, Self::Error> {
198	        let value = value.as_object().ok_or_else(|| {
199	            zerror!(
200	                "Configuration for plugin {} must be an object",
201	                name.as_ref()
202	            )
203	        })?;
204	        let required = value
205	            .get("__required__")
206	            .map(|r| {
207	                r.as_bool().ok_or_else(|| {
208	                    zerror!(
209	                        "`__required__` field of {}'s configuration must be a boolean",
210	                        name.as_ref()
211	                    )
212	                })
213	            })
214	            .unwrap_or(Ok(true))?;
215	        // TODO(fuzzypixelz): refactor this function's interface to get access to the configuration
216	        // source, this we can support spec syntax in the lib search dir.
217	        let backend_search_dirs = match value.get("backend_search_dirs") {
218	            Some(serde_json::Value::String(path)) => LibSearchDirs::from_paths(&[path.as_str()]),
219	            Some(serde_json::Value::Array(paths)) => {
220	                let mut specs = Vec::with_capacity(paths.len());
221	                for path in paths {
222	                    let serde_json::Value::String(path) = path else {
223	                        bail!(
224	                            "`backend_search_dirs` field of {}'s configuration must be a string \
225	                             or array of strings",
226	                            name.as_ref()
227	                        );
228	                    };
229	                    specs.push(path.clone());
230	                }
231	                LibSearchDirs::from_paths(&specs)
232	            }
233	            None => LibSearchDirs::default(),
234	            _ => bail!(
235	                "`backend_search_dirs` field of {}'s configuration must be a string or array of \
236	                 strings",
237	                name.as_ref()
238	            ),
239	        };
240	        let volumes = match value.get("volumes") {
241	            Some(configs) => VolumeConfig::try_from(name.as_ref(), configs)?,
242	            None => Vec::new(),
243	        };
244	        let storages = match value.get("storages") {
245	            Some(serde_json::Value::Object(configs)) => {
246	                let mut storages = Vec::with_capacity(configs.len());
247	                for (storage_name, config) in configs {
248	                    storages.push(StorageConfig::try_from(
249	                        name.as_ref(),
250	                        storage_name,
251	                        config,
252	                    )?)
253	                }
254	                storages
255	            }
256	            None => Vec::new(),
257	            _ => bail!(
258	                "`storages` field of `{}`'s configuration must be an object",
259	                name.as_ref()
260	            ),
261	        };
262	        Ok(PluginConfig {
263	            name: name.into(),
264	            required,
265	            backend_search_dirs,
266	            volumes,
267	            storages,
268	            rest: value
269	                .into_iter()
270	                .filter(|&(k, _v)| {
271	                    !["__required__", "backend_search_dirs", "volumes", "storages"]
272	                        .contains(&k.as_str())
273	                })
274	                .map(|(k, v)| (k.clone(), v.clone()))
275	                .collect(),
276	        })
277	    }
278	}
279	impl ConfigDiff {
280	    pub fn diffs(old: PluginConfig, new: PluginConfig) -> Vec<ConfigDiff> {
281	        let mut diffs = Vec::new();
282	        for old in &old.storages {
283	            if !new.storages.contains(old) {
284	                diffs.push(ConfigDiff::DeleteStorage(old.clone()))
285	            }
286	        }
287	        for old in &old.volumes {
288	            if !new.volumes.contains(old) {
289	                diffs.push(ConfigDiff::DeleteVolume(old.clone()))
290	            }
291	        }
292	        for new in new.volumes {
293	            if !old.volumes.contains(&new) {
294	                diffs.push(ConfigDiff::AddVolume(new))
295	            }
296	        }
297	        for new in new.storages {
298	            if !old.storages.contains(&new) {
299	                diffs.push(ConfigDiff::AddStorage(new))
300	            }
301	        }
302	        diffs
303	    }
304	}
305	impl VolumeConfig {
306	    pub fn to_json_value(&self) -> Value {
307	        let mut result: Map<String, Value> = (&self.rest).into();
308	        if let Some(paths) = &self.paths {
309	            result.insert(
310	                "__path__".into(),
311	                Value::Array(paths.iter().map(|p| Value::String(p.into())).collect()),
312	            );
313	        }
314	        if !self.required {
315	            result.insert("__required__".into(), Value::Bool(false));
316	        }
317	        Value::Object(result)
318	    }
319	    pub fn name(&self) -> &str {
320	        &self.name
321	    }
322	    pub fn backend(&self) -> &str {
323	        self.backend.as_deref().unwrap_or(&self.name)
324	    }
325	    pub fn paths(&self) -> Option<&[String]> {
326	        self.paths.as_deref()
327	    }
328	    fn try_from<V: AsObject>(plugin_name: &str, configs: &V) -> ZResult<Vec<Self>> {
329	        let configs = configs.as_object().ok_or_else(|| {
330	            zerror!(
331	                "Configuration for plugin `{}`'s `volumes` field must be an object",
332	                plugin_name
333	            )
334	        })?;
335	        let mut volumes = Vec::with_capacity(configs.len());
336	        for (name, config) in configs {
337	            let config = if let Value::Object(config) = config {
338	                config
339	            } else {
340	                bail!(
341	                    "`{}`'s `{}` backend configuration must be an object",
342	                    plugin_name,
343	                    name
344	                );
345	            };
346	            let backend = match config.get("backend") {
347	                None => None,
348	                Some(serde_json::Value::String(s)) => Some(s.clone()),
349	                _ => bail!(
350	                    "`backend` field of `{}`'s `{}` volume configuration must be a string",
351	                    plugin_name,
352	                    name
353	                ),
354	            };
355	            let paths = match config.get("__path__") {
356	                None => None,
357	                Some(serde_json::Value::String(s)) => Some(vec![s.clone()]),
358	                Some(serde_json::Value::Array(a)) => {
359	                    let mut paths = Vec::with_capacity(a.len());
360	                    for path in a {
361	                        if let serde_json::Value::String(path) = path {
362	                            paths.push(path.clone());
363	                        } else {
364	                            bail!(
365	                                "`path` field of `{}`'s `{}` volume configuration must be a \
366	                                 string or array of string",
367	                                plugin_name,
368	                                name
369	                            )
370	                        }
371	                    }
372	                    Some(paths)
373	                }
374	                _ => bail!(
375	                    "`path` field of `{}`'s `{}` volume configuration must be a string or array \
376	                     of string",
377	                    plugin_name,
378	                    name
379	                ),
380	            };
381	            let required = match config.get("__required__") {
382	                Some(serde_json::Value::Bool(b)) => *b,
383	                None => true,
384	                _ => bail!(
385	                    "`__required__` field of `{}`'s `{}` volume configuration must be a boolean",
386	                    plugin_name,
387	                    name
388	                ),
389	            };
390	            let rest_map: serde_json::Map<String, Value> = config
391	                .iter()
392	                .filter(|&(k, _v)| !["__path__", "__required__"].contains(&k.as_str()))
393	                .map(|(k, v)| (k.clone(), v.clone()))
394	                .collect();
395	            volumes.push(VolumeConfig {
396	                name: name.clone(),
397	                backend,
398	                paths,
399	                required,
400	                rest: rest_map.into(),
401	            })
402	        }
403	        Ok(volumes)
404	    }
405	}
406	impl StorageConfig {
407	    pub fn name(&self) -> &str {
408	        &self.name
409	    }
410	    pub fn to_json_value(&self) -> Value {
411	        let mut result = serde_json::Map::new();
412	        result.insert("key_expr".into(), Value::String(self.key_expr.to_string()));
413	        if let Some(s) = &self.strip_prefix {
414	            result.insert("strip_prefix".into(), Value::String(s.to_string()));
415	        }
416	
417	        result.insert(
418	            "volume".into(),
419	            match (&self.volume_cfg).into() {
420	                Value::Null => Value::String(self.volume_id.clone()),
421	                Value::Object(mut v) => {
422	                    v.insert("id".into(), self.volume_id.clone().into());
423	                    Value::Object(v)
424	                }
425	                _ => unreachable!(),
426	            },
427	        );
428	        Value::Object(result)
429	    }
430	    fn try_from<V: AsObject>(plugin_name: &str, storage_name: &str, config: &V) -> ZResult<Self> {
431	        let config = config.as_object().ok_or_else(|| {
432	            zerror!(
433	                "`storages` field of `{}`'s configuration must be an array of objects",
434	                plugin_name,
435	            )
436	        })?;
437	        let key_expr = match config.get("key_expr").and_then(|x| x.as_str()) {
438	            Some(s) => match keyexpr::new(s) {
439	                Ok(ke) => ke.to_owned(),
440	                Err(e) => bail!("key_expr='{}' is not a valid key-expression: {}", s, e),
441	            },
442	            None => {
443	                bail!(
444	                    "elements of the `storages` field of `{}`'s configuration must be objects \
445	                     with at least a `key_expr` string-typed field",
446	                    plugin_name,
447	                )
448	            }
449	        };
450	        let complete = match config.get("complete") {
451	            Some(Value::Bool(b)) => *b,
452	            Some(Value::String(s)) => match s.as_str() {
453	                "true" => true,
454	                "false" => false,
455	                e => {
456	                    bail!(
457	                        r#"complete='{}' is not a valid value. Only booleans or strings ('true','false') are accepted"#,
458	                        e
459	                    )
460	                }
461	            },
462	            None => false,
463	            _ => bail!(
464	                "Invalid type for field `complete` of storage `{}`. Only booleans or strings ('true','false') \
465	                 are accepted.",
466	                storage_name
467	            ),
468	        };
469	        let strip_prefix: Option<OwnedKeyExpr> = match config.get("strip_prefix") {
470	            Some(Value::String(s)) => {
471	                if !key_expr.starts_with(s) {
472	                    bail!(
473	                        r#"The specified "strip_prefix={}" is not a prefix of "key_expr={}""#,
474	                        s,
475	                        key_expr
476	                    )
477	                }
478	                match keyexpr::new(s.as_str()) {
479	                    Ok(ke) => {
480	                        if ke.is_wild() {
481	                            bail!(
482	                                r#"The specified "strip_prefix={}" contains wildcard characters (it shouldn't)"#,
483	                                ke
484	                            )
485	                        }
486	                        Some(ke.to_owned())
487	                    }
488	                    Err(e) => bail!("strip_prefix='{}' is not a valid key-expression: {}", s, e),
489	                }
490	            }
491	            None => None,
492	            _ => bail!(
493	                "Invalid type for field `strip_prefix` of storage `{}`. Only strings are accepted.",
494	                storage_name
495	            ),
496	        };
497	        let (volume_id, volume_cfg) = match config.get("volume") {
498	            Some(Value::String(volume_id)) => (volume_id.clone(), Value::Null),
499	            Some(Value::Object(volume)) => {
500	                let mut volume_id = None;
501	                let mut volume_cfg = serde_json::Map::new();
502	                for (key, value) in volume {
503	                    match (key.as_str(), value) {
504	                        ("id", Value::String(id)) => volume_id = Some(id.to_owned()),
505	                        ("id", _) => {}
506	                        _ => {
507	                            volume_cfg.insert(key.clone(), value.clone());
508	                        }
509	                    }
510	                }
511	                (
512	                    volume_id.ok_or_else(|| {
513	                        zerror!(
514	                            "`volume` value for storage `{}` is an object, but misses mandatory \
515	                             string-typed field `id`",
516	                            storage_name
517	                        )
518	                    })?,
519	                    volume_cfg.into(),
520	                )
521	            }
522	            None => bail!(
523	                "`volume` field missing for storage `{}`. This field is mandatory and accepts \
524	                 strings or objects with at least the `id` field",
525	                storage_name
526	            ),
527	            _ => bail!(
528	                "Invalid type for field `volume` of storage `{}`. Only strings or objects with at \
529	                 least the `id` field are accepted.",
530	                storage_name
531	            ),
532	        };
533	        let garbage_collection_config = match config.get("garbage_collection") {
534	            Some(s) => {
535	                let mut garbage_collection_config = GarbageCollectionConfig::default();
536	                if let Some(period) = s.get("period") {
537	                    let period = period.to_string().parse::<u64>();
538	                    if let Ok(period) = period {
539	                        garbage_collection_config.period = Duration::from_secs(period)
540	                    } else {
541	                        bail!(
542	                            "Invalid type for field `period` in `garbage_collection` of storage \
543	                             `{}`. Only integer values are accepted.",
544	                            plugin_name
545	                        )
546	                    }
547	                }
548	                if let Some(lifespan) = s.get("lifespan") {
549	                    let lifespan = lifespan.to_string().parse::<u64>();
550	                    if let Ok(lifespan) = lifespan {
551	                        garbage_collection_config.lifespan = Duration::from_secs(lifespan)
552	                    } else {
553	                        bail!(
554	                            "Invalid type for field `lifespan` in `garbage_collection` of storage \
555	                             `{}`. Only integer values are accepted.",
556	                            plugin_name
557	                        )
558	                    }
559	                }
560	                garbage_collection_config
561	            }
562	            None => GarbageCollectionConfig::default(),
563	        };
564	        let replication = match config.get("replication") {
565	            Some(s) => {
566	                let mut replication = ReplicaConfig::default();
567	                if let Some(p) = s.get("interval") {
568	                    let p = p.to_string().parse::<f64>();
569	                    if let Ok(p) = p {
570	                        replication.interval = Duration::from_secs_f64(p);
571	                    } else {
572	                        bail!(
573	                            "Invalid type for field `interval` in `replica_config` of storage \
574	                             `{}`. Expecting integer or floating point number.",
575	                            plugin_name
576	                        )
577	                    }
578	                }
579	                if let Some(p) = s.get("sub_intervals") {
580	                    let p = p.to_string().parse::<usize>();
581	                    if let Ok(p) = p {
582	                        replication.sub_intervals = p;
583	                    } else {
584	                        bail!(
585	                            "Invalid type for field `sub_intervals` in `replica_config` of \
586	                             storage `{}`. Only integer values are accepted.",
587	                            plugin_name
588	                        )
589	                    }
590	                }
591	                if let Some(d) = s.get("hot") {
592	                    let d = d.to_string().parse::<u64>();
593	                    if let Ok(d) = d {
594	                        replication.hot = d;
595	                    } else {
596	                        bail!(
597	                            "Invalid type for field `hot` in `replica_config` of storage `{}`. \
598	                             Only integer values are accepted.",
599	                            plugin_name
600	                        )
601	                    }
602	                }
603	                if let Some(d) = s.get("warm") {
604	                    let d = d.to_string().parse::<u64>();
605	                    if let Ok(d) = d {
606	                        replication.warm = d;
607	                    } else {
608	                        bail!(
609	                            "Invalid type for field `warm` in `replica_config` of storage `{}`. \
610	                             Only integer values are accepted.",
611	                            plugin_name
612	                        )
613	                    }
614	                }
615	                if let Some(p) = s.get("propagation_delay") {
616	                    let p = p.to_string().parse::<u64>();
617	                    if let Ok(p) = p {
618	                        let propagation_delay = Duration::from_millis(p);
619	                        if (replication.interval - propagation_delay) < propagation_delay {
620	                            bail!(
621	                                "Invalid value for field `propagation_delay`: its value is too \
622	                                 high compared to the `interval`, consider increasing the \
623	                                 `interval` to at least twice its value (i.e. {}).",
624	                                p as f64 * 2.0 / 1000.0
625	                            );
626	                        }
627	
628	                        replication.propagation_delay = propagation_delay;
629	                    } else {
630	                        bail!(
631	                            "Invalid type for field `propagation_delay` in `replica_config` of \
632	                             storage `{}`. Only integer values are accepted.",
633	                            plugin_name
634	                        )
635	                    }
636	                }
637	                Some(replication)
638	            }
639	            None => None,
640	        };
641	        Ok(StorageConfig {
642	            name: storage_name.into(),
643	            key_expr,
644	            complete,
645	            strip_prefix,
646	            volume_id,
647	            volume_cfg: volume_cfg.into(),
648	            garbage_collection_config,
649	            replication,
650	        })
651	    }
652	}
653	impl PartialEq for VolumeConfig {
654	    fn eq(&self, other: &Self) -> bool {
655	        self.name == other.name && self.paths == other.paths && self.rest == other.rest
656	    }
657	}
658	#[derive(Debug)]
659	pub enum PrivacyGetResult<T> {
660	    NotFound,
661	    Private(T),
662	    Public(T),
663	    Both { public: T, private: T },
664	}
665	pub trait PrivacyTransparentGet<T> {
666	    fn get_private(&self, key: &str) -> PrivacyGetResult<&T>;
667	}
668	impl PrivacyTransparentGet<serde_json::Value> for serde_json::Map<String, serde_json::Value> {
669	    fn get_private(&self, key: &str) -> PrivacyGetResult<&serde_json::Value> {
670	        use PrivacyGetResult::*;
671	        match (
672	            self.get(key),
673	            self.get("private")
674	                .and_then(|f| f.as_object().and_then(|f| f.get(key))),
675	        ) {
676	            (None, None) => NotFound,
677	            (Some(a), None) => Public(a),
678	            (None, Some(a)) => Private(a),
679	            (Some(a), Some(b)) => Both {
680	                public: a,
681	                private: b,
682	            },
683	        }
684	    }
685	}
