319	impl RunningPluginTrait for StorageRuntime {
320	    fn config_checker(
321	        &self,
322	        _: &str,
323	        old: &JsonKeyValueMap,
324	        new: &JsonKeyValueMap,
325	    ) -> ZResult<Option<JsonKeyValueMap>> {
326	        let old: serde_json::Map<String, serde_json::Value> = old.into();
327	        let new: serde_json::Map<String, serde_json::Value> = new.into();
328	        let name = { zlock!(self.0).name.clone() };
329	        let old = PluginConfig::try_from((&name, &old))?;
330	        let new = PluginConfig::try_from((&name, &new))?;
331	        tracing::debug!("config change requested for plugin '{}'", name);
332	        tracing::debug!("old config: {:?}", &old);
333	        tracing::debug!("new config: {:?}", &new);
334	        let diffs = ConfigDiff::diffs(old, new);
335	        tracing::debug!("applying diff: {:?}", &diffs);
336	        { zlock!(self.0).update(diffs) }?;
337	        tracing::debug!("applying diff done");
338	        Ok(None)
339	    }
340	
341	    fn adminspace_getter<'a>(
342	        &'a self,
343	        key_expr: &'a KeyExpr<'a>,
344	        plugin_status_key: &str,
345	    ) -> ZResult<Vec<Response>> {
346	        let mut responses = Vec::new();
347	        let mut key = String::from(plugin_status_key);
348	        // TODO: to be removed when "__version__" is implemented in admin space
349	        with_extended_string(&mut key, &["/version"], |key| {
350	            if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
351	                responses.push(Response::new(
352	                    key.clone(),
353	                    StoragesPlugin::PLUGIN_VERSION.into(),
354	                ))
355	            }
356	        });
357	        let guard = self.0.lock().unwrap();
358	        with_extended_string(&mut key, &["/volumes/"], |key| {
359	            for plugin in guard.plugins_manager.started_plugins_iter() {
360	                with_extended_string(key, &[plugin.id()], |key| {
361	                    with_extended_string(key, &["/__path__"], |key| {
362	                        if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
363	                            responses.push(Response::new(key.clone(), plugin.path().into()))
364	                        }
365	                    });
366	                    if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
367	                        responses.push(Response::new(
368	                            key.clone(),
369	                            plugin.instance().get_admin_status().into(),
370	                        ))
371	                    }
372	                });
373	            }
374	        });
375	        with_extended_string(&mut key, &["/storages/"], |key| {
376	            for storages in guard.storages.values() {
377	                for (storage, handle) in storages {
378	                    with_extended_string(key, &[storage], |key| {
379	                        if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
380	                            if let Some(value) = tokio::task::block_in_place(|| {
381	                                TOKIO_RUNTIME.block_on(async {
382	                                    let (tx, mut rx) = tokio::sync::mpsc::channel(1);
383	                                    let _ = handle.send(StorageMessage::GetStatus(tx));
384	                                    rx.recv().await
385	                                })
386	                            }) {
387	                                responses.push(Response::new(key.clone(), value))
388	                            }
389	                        }
390	                    })
391	                }
392	            }
393	        });
394	        Ok(responses)
395	    }
396	}
397	
398	const BACKEND_LIB_PREFIX: &str = "zenoh_backend_";
399	const MEMORY_BACKEND_NAME: &str = "memory";
400	
401	fn with_extended_string<R, F: FnMut(&mut String) -> R>(
402	    prefix: &mut String,
403	    suffixes: &[&str],
404	    mut closure: F,
405	) -> R {
406	    let prefix_len = prefix.len();
407	    for suffix in suffixes {
408	        prefix.push_str(suffix);
409	    }
410	    let result = closure(prefix);
411	    prefix.truncate(prefix_len);
412	    result
413	}
414	
415	/// Returns the key expression stripped of the provided prefix.
416	///
417	/// If no prefix is provided this function returns the key expression untouched.
418	///
419	/// If `None` is returned, it indicates that the key expression is equal to the prefix.
420	///
421	/// This function will internally call [strip_prefix], see its documentation for possible outcomes.
422	///
423	/// # Errors
424	///
425	/// This function will return an error if:
426	/// - The provided prefix contains a wildcard.
427	///   NOTE: The configuration of a Storage is checked and will reject any prefix that contains a
428	///   wildcard. In theory, this error should never occur.
429	/// - The key expression is not prefixed by the provided prefix.
430	/// - The resulting stripped key is not a valid key expression (this should, in theory, never
431	///   happen).
432	///
433	/// [strip_prefix]: zenoh::key_expr::keyexpr::strip_prefix()
434	pub fn strip_prefix(
435	    maybe_prefix: Option<&OwnedKeyExpr>,
436	    key_expr: &KeyExpr<'_>,
437	) -> ZResult<Option<OwnedKeyExpr>> {
438	    match maybe_prefix {
439	        None => Ok(Some(key_expr.clone().into())),
440	        Some(prefix) => {
441	            if prefix.is_wild() {
442	                bail!(
443	                    "Prefix < {} > contains a wild character (\"**\" or \"*\")",
444	                    prefix
445	                );
446	            }
447	
448	            // `key_expr.strip_prefix` returns empty vec if `key_expr == prefix`,
449	            // but also returns empty vec if `prefix` is not a prefix to `key_expr`.
450	            // First case needs to be handled before calling `key_expr.strip_prefix`
451	            if key_expr.as_str().eq(prefix.as_str()) {
452	                return Ok(None);
453	            }
454	
455	            match key_expr.strip_prefix(prefix).as_slice() {
456	                // NOTE: `stripped_key_expr.is_empty()` should be impossible as "" is not a valid key expression
457	                [stripped_key_expr] => OwnedKeyExpr::from_str(stripped_key_expr).map(Some),
458	                _ => bail!("Failed to strip prefix < {} > from: {}", prefix, key_expr),
459	            }
460	        }
461	    }
462	}
463	
464	/// Returns the key with an additional prefix, if both were provided.
465	///
466	/// If no prefix is provided, this function returns `maybe_stripped_key`.
467	///
468	/// If no key is provided, this function returns the `maybe_prefix`.
469	///
470	/// If a prefix is provided, this function returns the concatenation of both.
471	///
472	/// # Error
473	///
474	/// This function will return an error if both `maybe_prefix` and `maybe_stripped_key` are equal to
475	/// `None`. This situation can happen if (i) the "backend" associated to a Storage is first started
476	/// with a `strip_prefix` set to some value, (ii) a key equal to the `strip_prefix` is published
477	/// (hence storing `None`) then (iii) the Storage is stopped and the "backend" is associated to
478	/// another Storage without a `strip_prefix` configured.
479	pub fn prefix(
480	    maybe_prefix: Option<&OwnedKeyExpr>,
481	    maybe_stripped_key: Option<&OwnedKeyExpr>,
482	) -> ZResult<OwnedKeyExpr> {
483	    match (maybe_prefix, maybe_stripped_key) {
484	        (Some(prefix), Some(stripped_key)) => Ok(prefix / stripped_key),
485	        (Some(prefix), None) => Ok(prefix.clone()),
486	        (None, Some(key)) => Ok(key.clone()),
487	        (None, None) => bail!("Fatal internal error: empty prefix with empty key"),
488	    }
489	}
